  compareOwnPointWithPackagePrice() {
      const functionName = 'compareOwnPointWithPackage';
      const messageLog = 'call payment service';
      let totalPoint;
      let apiUrl = environment.API_URI + ApiNameConstants.BS_PAYMENT_WALLET_BY_USER;
      try {
        this.commonService.getData(apiUrl, functionName, messageLog).subscribe(res => {
          if (res && res.data) {
            let wallet = res.data;
            totalPoint = wallet.totalPoint;
            let price = this.upgradePackage.price;

            if (price > totalPoint) {
              // request topup
              this.popupRequestTopup.openPopup();
            } else {
              wallet.price = price
              this.updateWallet(wallet);
              this.addingTransactionHis();
              const currentDate = new Date();
              const premiumExpDate = new Date(currentDate);
              premiumExpDate.setMonth(currentDate.getMonth() + this.upgradePackage.type);
              this.userItem.premiumExpDate = premiumExpDate;
              this.onUpdateUser(null);
              // adding new record to transaction history + update user-> premiumexpdate
              // totalPoint = totalPoint - price
            }
          } else {
            this.popupRequestTopup.openPopup();
          }
        });
      } catch(e) {
        console.log(e);
      }
    }

