    buildSelectedItem(key: any, items: any) {
        let selectedItem = null;
        if (!this.userItem || !this.userItem[key]) return;
        let val = this.userItem[key];
        for (let i = 0; i < items.length; i++) {
            if (items[i].code == val) {
                selectedItem = items[i];
                break;
            }
        }
        return selectedItem;
    }

